/**
 * Repair auto-generated approved ODs that are linked on previous AttendanceDaily date.
 *
 * Target ODs:
 * - placeVisited: "Organization Campus (Auto)"
 * - purpose: "Work on Holiday/Week-off"
 * - status: "approved"
 *
 * What it does:
 * 1) Finds ODs where correct IST day is not linked, but previous day has odDetails.odId.
 * 2) Moves/attaches OD link to the correct IST date AttendanceDaily.
 * 3) Optionally "revoke + reapprove history cleanup":
 *    - keeps only submit entry + one final approved entry in workflow.history
 *    - keeps OD status as approved
 * 4) Optional recalc for wrong and correct dates.
 *
 * Usage (from backend/):
 *   node scripts/revoke_reapprove_auto_ods_by_date_link.js --month 2026-04
 *   node scripts/revoke_reapprove_auto_ods_by_date_link.js --month 2026-04 --apply
 *   node scripts/revoke_reapprove_auto_ods_by_date_link.js --month 2026-04 --apply --recalc
 *   node scripts/revoke_reapprove_auto_ods_by_date_link.js --month 2026-04 --apply --emps 2237,2213
 */

const path = require('path');
const mongoose = require('mongoose');
require('dotenv').config({ path: path.join(__dirname, '../.env') });

require('../departments/model/Department');
require('../designations/model/Designation');
const OD = require('../leaves/model/OD');
const AttendanceDaily = require('../attendance/model/AttendanceDaily');
const Employee = require('../employees/model/Employee');
const LeaveRegisterYear = require('../leaves/model/LeaveRegisterYear');
const leaveRegisterService = require('../leaves/services/leaveRegisterService');
const { isHolidayOrWeekOff } = require('../leaves/services/odHolidayApplyContextService');
const dateCycleService = require('../leaves/services/dateCycleService');
const { createISTDate, extractISTComponents } = require('../shared/utils/dateUtils');

const APPLY = process.argv.includes('--apply');
const RECALC = process.argv.includes('--recalc');
const QUIET = process.argv.includes('--quiet');

function getArg(flag) {
  const i = process.argv.indexOf(flag);
  if (i >= 0 && process.argv[i + 1] && !String(process.argv[i + 1]).startsWith('--')) return process.argv[i + 1];
  return null;
}

function asEmpVariants(empNo) {
  const raw = String(empNo || '').trim();
  return [...new Set([raw, raw.toUpperCase()].filter(Boolean))];
}

function prevDateStr(istDateStr) {
  const d = new Date(`${istDateStr}T12:00:00+05:30`);
  d.setDate(d.getDate() - 1);
  return extractISTComponents(d).dateStr;
}

function buildOdDetails(od) {
  return {
    odStartTime: od.odStartTime || null,
    odEndTime: od.odEndTime || null,
    durationHours: od.durationHours ?? null,
    odType: od.odType_extended || (od.isHalfDay ? 'half_day' : 'full_day'),
    odId: od._id,
  };
}

function pickFinalApprovalSnapshot(od) {
  const chain = Array.isArray(od?.workflow?.approvalChain) ? od.workflow.approvalChain : [];
  const approvedSteps = chain
    .filter((s) => s && s.status === 'approved')
    .sort((a, b) => (Number(a.stepOrder) || 0) - (Number(b.stepOrder) || 0));
  const last = approvedSteps[approvedSteps.length - 1] || null;
  if (!last) return null;
  return {
    step: String(last.role || 'final_authority'),
    action: 'approved',
    actionBy: last.actionBy || null,
    actionByName: last.actionByName || 'Unknown',
    actionByRole: last.actionByRole || String(last.role || 'final_authority'),
    comments: last.comments || 'Approved (repaired link)',
    timestamp: last.updatedAt || od.updatedAt || new Date(),
  };
}

async function recalc(empNo, dates) {
  if (!APPLY || !RECALC || !dates.length) return;
  const { recalculateOnAttendanceUpdate } = require('../attendance/services/summaryCalculationService');
  const norm = String(empNo || '').trim().toUpperCase();
  for (const d of [...new Set(dates)]) {
    try {
      await recalculateOnAttendanceUpdate(norm, d);
    } catch (e) {
      console.error(`[recalc] failed emp=${norm} date=${d}:`, e.message || e);
    }
  }
}

async function hasCclCreditForOdDay(employeeId, dateStr) {
  const dayStart = createISTDate(dateStr, '00:00');
  const dayEnd = createISTDate(dateStr, '23:59');
  const row = await LeaveRegisterYear.findOne({
    employeeId,
    months: {
      $elemMatch: {
        transactions: {
          $elemMatch: {
            leaveType: 'CCL',
            transactionType: 'CREDIT',
            autoGeneratedType: 'OD_HOLIDAY_WO_CO_CREDIT',
            startDate: { $gte: dayStart, $lte: dayEnd },
          },
        },
      },
    },
  })
    .select('_id')
    .lean();
  return !!row;
}

async function dayQualifiesForCo(od, empNo, dateStr) {
  if (await isHolidayOrWeekOff(empNo, dateStr)) return true;
  const variants = asEmpVariants(empNo);
  const att = await AttendanceDaily.findOne({
    date: dateStr,
    employeeNumber: variants.length ? { $in: variants } : String(empNo || '').toUpperCase(),
  })
    .select('status')
    .lean();
  const st = String(att?.status || '').toUpperCase();
  if (st === 'HOLIDAY' || st === 'WEEK_OFF') return true;
  const fromStr = extractISTComponents(od.fromDate).dateStr;
  if (od.isCOEligible === true && dateStr === fromStr) return true;
  return false;
}

async function ensureCompOffCredit(od, empNo, day, dryRun) {
  if (!od?.employeeId) {
    return { qualifies: false, hasCredit: false, creditedNow: false };
  }
  const qualifies = await dayQualifiesForCo(od, empNo, day);
  if (!qualifies) return { qualifies: false, hasCredit: false, creditedNow: false };

  const hasCredit = await hasCclCreditForOdDay(od.employeeId, day);
  if (hasCredit || dryRun) return { qualifies: true, hasCredit, creditedNow: false };

  const emp = await Employee.findById(od.employeeId)
    .select('_id emp_no employee_name doj is_active division_id department_id designation_id')
    .populate('department_id', 'name')
    .populate('designation_id', 'name')
    .lean();
  if (!emp) return { qualifies: true, hasCredit: false, creditedNow: false };

  const increment = od.isHalfDay || od.odType_extended === 'half_day' ? 0.5 : 1;
  await leaveRegisterService.addTransaction({
    employeeId: emp._id,
    empNo: emp.emp_no,
    employeeName: emp.employee_name || 'N/A',
    designation: emp.designation_id?.name || 'N/A',
    department: emp.department_id?.name || 'N/A',
    divisionId: emp.division_id,
    departmentId: emp.department_id?._id || emp.department_id,
    dateOfJoining: emp.doj || new Date(),
    employmentStatus: emp.is_active ? 'active' : 'inactive',
    leaveType: 'CCL',
    transactionType: 'CREDIT',
    startDate: createISTDate(day),
    endDate: createISTDate(day),
    days: increment,
    reason: `Compensatory Off for approved OD on holiday/week-off (${day})`,
    status: 'APPROVED',
    autoGenerated: true,
    autoGeneratedType: 'OD_HOLIDAY_WO_CO_CREDIT',
    applicationDate: new Date(),
    approvalDate: new Date(),
    approvedBy: null,
    includedInPayroll: false,
    operationLabel: 'OD_REAPPROVE_REPAIR',
  });
  return { qualifies: true, hasCredit: false, creditedNow: true };
}

async function main() {
  if (!process.env.MONGODB_URI) {
    console.error('MONGODB_URI missing in backend/.env');
    process.exit(1);
  }

  const monthArg = getArg('--month');
  if (!monthArg || !/^\d{4}-(0[1-9]|1[0-2])$/.test(monthArg)) {
    console.error('Pass --month YYYY-MM');
    process.exit(1);
  }

  const empsArg = getArg('--emps');
  const scopedEmps = empsArg
    ? empsArg
        .split(/[,;]\s*|\s+/)
        .map((x) => String(x || '').trim().toUpperCase())
        .filter(Boolean)
    : null;

  await mongoose.connect(process.env.MONGODB_URI);

  const periodInfo = await dateCycleService.getPeriodInfo(createISTDate(`${monthArg}-15`));
  const startDateStr = extractISTComponents(periodInfo.payrollCycle.startDate).dateStr;
  const endDateStr = extractISTComponents(periodInfo.payrollCycle.endDate).dateStr;

  console.log(`Mode: ${APPLY ? 'APPLY' : 'DRY-RUN'}${RECALC ? ' (+recalc)' : ''}`);
  console.log(JSON.stringify({ month: monthArg, payroll_window: `${startDateStr}..${endDateStr}` }, null, 2));

  const odQuery = {
    status: 'approved',
    isActive: true,
    purpose: 'Work on Holiday/Week-off',
    placeVisited: 'Organization Campus (Auto)',
    fromDate: { $lte: createISTDate(endDateStr, '23:59') },
    toDate: { $gte: createISTDate(startDateStr, '00:00') },
  };

  const ods = await OD.find(odQuery)
    .select('_id employeeId emp_no fromDate toDate status isHalfDay halfDayType odType_extended durationHours odStartTime odEndTime isCOEligible workflow updatedAt')
    .lean();

  let checked = 0;
  let affected = 0;
  let fixed = 0;
  let skipped = 0;
  let cclExpected = 0;
  let cclMissing = 0;
  let cclCredited = 0;

  for (const od of ods) {
    const empNo = String(od.emp_no || '').trim().toUpperCase();
    if (!empNo) {
      skipped += 1;
      continue;
    }
    if (scopedEmps && scopedEmps.length && !scopedEmps.includes(empNo)) continue;

    const fromIst = extractISTComponents(od.fromDate).dateStr;
    const toIst = extractISTComponents(od.toDate).dateStr;
    if (fromIst !== toIst) {
      skipped += 1;
      continue;
    }

    checked += 1;
    const correctDate = fromIst;
    const wrongDate = prevDateStr(correctDate);
    const variants = asEmpVariants(empNo);

    const [correctDaily, wrongDaily] = await Promise.all([
      AttendanceDaily.findOne({
        employeeNumber: { $in: variants },
        date: correctDate,
      }),
      AttendanceDaily.findOne({
        employeeNumber: { $in: variants },
        date: wrongDate,
      }),
    ]);

    const correctHas = !!(correctDaily?.odDetails?.odId && String(correctDaily.odDetails.odId) === String(od._id));
    const wrongHas = !!(wrongDaily?.odDetails?.odId && String(wrongDaily.odDetails.odId) === String(od._id));

    if (correctHas || !wrongHas) {
      const cclState = await ensureCompOffCredit(od, empNo, correctDate, !APPLY);
      if (cclState.qualifies) cclExpected += 1;
      if (cclState.qualifies && !cclState.hasCredit) cclMissing += 1;
      if (cclState.creditedNow) cclCredited += 1;
      continue;
    }
    affected += 1;

    if (!QUIET) {
      console.log(`[candidate] od=${od._id} emp=${empNo} wrong=${wrongDate} -> correct=${correctDate}`);
    }

    if (!APPLY) continue;

    const odDoc = await OD.findById(od._id);
    const wrongDoc = await AttendanceDaily.findById(wrongDaily._id);
    let correctDoc = correctDaily ? await AttendanceDaily.findById(correctDaily._id) : null;

    if (!correctDoc) {
      correctDoc = new AttendanceDaily({
        employeeNumber: empNo,
        date: correctDate,
        shifts: [],
      });
    }

    // Remove OD link from previous-day row only if this OD is currently linked there.
    if (wrongDoc?.odDetails?.odId && String(wrongDoc.odDetails.odId) === String(od._id)) {
      wrongDoc.set('odDetails', null);
      wrongDoc.set('odHours', 0);
      await wrongDoc.save();
    }

    // Add OD link on correct IST day.
    correctDoc.set('odDetails', buildOdDetails(od));
    if (String(od.odType_extended || '').toLowerCase() === 'hours') {
      correctDoc.set('odHours', Number(od.durationHours) || 0);
    }
    correctDoc.markModified('odDetails');
    await correctDoc.save();

    // Revoke + reapprove history cleanup:
    // keep "submitted" event + one final "approved" event snapshot.
    if (odDoc) {
      const submitted = Array.isArray(odDoc.workflow?.history)
        ? odDoc.workflow.history.find((h) => String(h?.action) === 'submitted')
        : null;
      const finalApproved = pickFinalApprovalSnapshot(odDoc);

      const newHistory = [];
      if (submitted) newHistory.push(submitted);
      if (finalApproved) newHistory.push(finalApproved);
      if (newHistory.length === 0) {
        newHistory.push({
          step: 'system',
          action: 'approved',
          actionBy: null,
          actionByName: 'Script',
          actionByRole: 'system',
          comments: 'OD date-link repaired and approval history normalized.',
          timestamp: new Date(),
        });
      }

      if (!odDoc.workflow) odDoc.workflow = {};
      odDoc.workflow.history = newHistory;
      odDoc.status = 'approved';
      odDoc.markModified('workflow');
      await odDoc.save();
    }

    await recalc(empNo, [wrongDate, correctDate]);

    const cclState = await ensureCompOffCredit(odDoc || od, empNo, correctDate, !APPLY);
    if (cclState.qualifies) cclExpected += 1;
    if (cclState.qualifies && !cclState.hasCredit) cclMissing += 1;
    if (cclState.creditedNow) cclCredited += 1;

    fixed += 1;
    if (!QUIET) console.log(`[fixed] od=${od._id} emp=${empNo} moved to ${correctDate}`);
  }

  console.log('---');
  console.log(
    JSON.stringify(
      {
        checked_single_day_auto_approved_ods: checked,
        affected_wrong_previous_day_link: affected,
        fixed_in_apply: fixed,
        skipped_multi_day_or_invalid: skipped,
        ccl_credit: {
          expected_holiday_or_weekoff_od_days: cclExpected,
          missing_before_apply_or_dryrun: cclMissing,
          credited_now_in_apply: cclCredited,
        },
      },
      null,
      2
    )
  );

  await mongoose.disconnect();
}

main().catch(async (e) => {
  console.error(e.message || e);
  try {
    await mongoose.disconnect();
  } catch {}
  process.exit(1);
});

